import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.util.Scanner;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input to prevent XSS
        String sanitizedInput = ESAPI.encoder().encodeForHTML(userInput);

        String greetingMessage = "Hello, " + sanitizedInput + "!";

        // Display the sanitized greeting message
        try {
            System.out.println(ESAPI.encoder().encodeForHTML(greetingMessage));
        } catch (EncodingException e) {
            System.err.println("Error encoding output: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
